 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import {
 4	  DescriptionList,
 5	  DescriptionListDescription,
 6	  DescriptionListGroup,
 7	  DescriptionListTerm,
 8	} from '@patternfly/react-core';
 9	import { PipelineRunKind } from '../../types';
10	import { StartedByAnnotation, StartedByLabel } from '../../consts';
11	import {
12	  getGroupVersionKindForModel,
13	  ResourceLink,
14	} from '@openshift-console/dynamic-plugin-sdk';
15	import { EventListenerModel } from '../../models';
16	
17	type TriggeredByProps = {
18	  pipelineRun: PipelineRunKind;
19	};
20	
21	const TriggeredBySection: React.FC<TriggeredByProps> = (props) => {
22	  const { t } = useTranslation('plugin__pipelines-console-plugin');
23	  const {
24	    pipelineRun: {
25	      metadata: { annotations, namespace, labels },
26	    },
27	  } = props;
28	
29	  const manualTrigger = annotations?.[StartedByAnnotation.user];
30	  const autoTrigger = labels?.[StartedByLabel.triggers];
31	
32	  if (!manualTrigger && !autoTrigger) {
33	    return null;
34	  }
35	
36	  let value = null;
37	  if (manualTrigger) {
38	    value = manualTrigger;
39	  } else if (autoTrigger) {
40	    value = (
41	      <ResourceLink
42	        groupVersionKind={getGroupVersionKindForModel(EventListenerModel)}
43	        name={autoTrigger}
44	        namespace={namespace}
45	      />
46	    );
47	  } else {
48	    return null;
49	  }
50	
51	  return (
52	    <DescriptionList className="pf-v6-u-mt-md">
53	      <DescriptionListGroup>
54	        <DescriptionListTerm>{t('Triggered by')}:</DescriptionListTerm>
55	        <DescriptionListDescription>{value}</DescriptionListDescription>
56	      </DescriptionListGroup>
57	    </DescriptionList>
58	  );
59	};
60	
61	export default TriggeredBySection;

